use strict;
use warnings;

sub linear_search {
    my ($arr_ref, $target) = @_;
    my @arr = @$arr_ref;

    for my $i (0 .. $#arr) {
        return $i if $arr[$i] == $target;
    }
    return -1;
}

sub binary_search {
    my ($arr_ref, $target) = @_;
    my @arr = @$arr_ref;
    my ($left, $right) = (0, $#arr);

    while ($left <= $right) {
        my $mid = int(($left + $right) / 2);

        if ($arr[$mid] == $target) {
            return $mid;
        } elsif ($arr[$mid] < $target) {
            $left = $mid + 1;
        } else {
            $right = $mid - 1;
        }
    }
    return -1;
}

my @numbers = (4, 12, 7, 23, 9, 1, 18);
my $target = 23;

my $linear_result = linear_search(\@numbers, $target);
print "Dogrusal arama: $target indeks $linear_result'de bulundu\n";

# Binary arama icin dizi siralanmali
my @sorted_numbers = sort { $a <=> $b } @numbers;

my $binary_result = binary_search(\@sorted_numbers, $target);
print "Binary arama: $target indeks $binary_result'de bulundu\n";

my $not_found = linear_search(\@numbers, 99);
print "\n99 araniyor (bulunamayacak): $not_found\n";

# Perl'in grep ile arama
my @found = grep { $_ == $target } @numbers;
print "\ngrep ile bulundu mu: " . (scalar(@found) > 0 ? "evet" : "hayir") . "\n";
